from langchain.tools import StructuredTool
import requests

def classify_product(product_description: str, origin_country: str = 'CN') -> dict:
    resp = requests.post(
        'https://web-production-c9da4.up.railway.app/v1/customs/classify',
        headers={'X-API-Key': 'YOUR_KEY', 'Content-Type': 'application/json'},
        json={'items': [{'description': product_description, 'origin_country': origin_country}]}
    )
    return resp.json()

customs_tool = StructuredTool.from_function(
    func=classify_product,
    name='thai_customs_classifier',
    description='Classify products for Thai customs import. Returns HS code, duty rate, FTA rates, OGA requirements.'
)
